import{_ as e,o as r,c as t,a2 as p}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"盈亏页面释义","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/pnl-page.md","filePath":"zh-CN/portfolio-and-statements/pnl-page.md"}'),o={name:"portfolio-and-statements/pnl-page.md"};function h(l,a,i,n,d,s){return r(),t("div",null,[...a[0]||(a[0]=[p('<h1 id="盈亏页面释义" tabindex="-1">盈亏页面释义 <a class="header-anchor" href="#盈亏页面释义" aria-label="Permalink to &quot;盈亏页面释义&quot;">​</a></h1><p>累计盈亏、持仓盈亏、当日盈亏、收益率计算方法及常见问题解答。</p><h2 id="一、盈亏分析入口" tabindex="-1">一、盈亏分析入口 <a class="header-anchor" href="#一、盈亏分析入口" aria-label="Permalink to &quot;一、盈亏分析入口&quot;">​</a></h2><p>入口一：点击资产总览的空白处，选择「盈亏分析」</p><p>入口二：点击资产 - 全部功能，选择「盈亏分析」</p><h2 id="二、盈亏分析功能说明" tabindex="-1">二、盈亏分析功能说明 <a class="header-anchor" href="#二、盈亏分析功能说明" aria-label="Permalink to &quot;二、盈亏分析功能说明&quot;">​</a></h2><p>在盈亏分析页可以查看收益情况，全方位回顾交易盈亏情况。主要功能包括：累计盈亏金额、累计收益率、跑赢大盘指数情况、每日收益明细、个股收益明细，以及资产变动等。</p><h2 id="三、盈亏相关字段说明" tabindex="-1">三、盈亏相关字段说明 <a class="header-anchor" href="#三、盈亏相关字段说明" aria-label="Permalink to &quot;三、盈亏相关字段说明&quot;">​</a></h2><h3 id="累计盈亏" tabindex="-1">累计盈亏 <a class="header-anchor" href="#累计盈亏" aria-label="Permalink to &quot;累计盈亏&quot;">​</a></h3><p>累计盈亏统计的是因为交易或企业行动等引起的账户盈亏总额。</p><p>累计盈亏 = 期间每日盈亏合计</p><p>每日盈亏 = 美元盈亏 × 港币汇率 + 港币盈亏</p><p>每日盈亏 = 期末总资产 - 期初总资产 - 期间净投入</p><p>由于长桥为综合账户，计算盈亏时会转化为港币进行计算，中间由于汇率波动，会导致无任何交易的情况下盈亏金额也会变动。</p><p>期末总资产（HKD 等值）= 美元总资产 × 期末汇率 + 港币总资产 × 期末汇率</p><p>期初总资产（HKD 等值）= 美元总资产 × 期初汇率 + 港币总资产 × 期初汇率</p><p>期间净投入（以下业务作为投入，不记录在盈亏中）：出入金、主子账户转账、转仓、主子账户转仓、兑换、融资利息规则、现金卡奖励。</p><h3 id="持仓盈亏-浮动盈亏" tabindex="-1">持仓盈亏（浮动盈亏） <a class="header-anchor" href="#持仓盈亏-浮动盈亏" aria-label="Permalink to &quot;持仓盈亏（浮动盈亏）&quot;">​</a></h3><p>持仓盈亏也为「浮动盈亏」，是记录从开仓到现在总的盈亏（不考虑交易手续费）。</p><p>持仓盈亏（多头仓位）=（现价 - 成本）× 当前数量</p><p>持仓盈亏（空头仓位）=（成本 - 现价）× 当前数量</p><p>成本：目前系统支持两种成本价选择，分别是摊薄成本和平均开仓成本。默认是摊薄成本，如需更改可在「资产首页」-「全部功能」-「资产设置」-「成本计算方式」进行选择。</p><h3 id="当日盈亏" tabindex="-1">当日盈亏 <a class="header-anchor" href="#当日盈亏" aria-label="Permalink to &quot;当日盈亏&quot;">​</a></h3><p>当日盈亏的含义为从上一个交易日的收盘价到当前交易日时段的累计盈亏。</p><p>计算公式：当日盈亏 = 最新价 × 当前持仓数量 - 昨收价 × 昨收持仓数量 + 当日卖出成交额 - 当日买入成交额</p><p>港股：根据香港时间 T 日 9 点～T+1 日 9 点之间，股价变更及交易行为计算当日盈亏。</p><p>美股：会受到盘前盘后、夜盘的因素影响，情况更复杂。<br> 开启夜盘：统计美东时间 T 日 20 点～T+1 日 20 点，最新价纳入夜盘期间价格。<br> 关闭夜盘：统计美东时间 T 日 4 点～T+1 日 4 点，夜盘期间价格不纳入计算。<br> 开启盘前盘后：最新价纳入盘前盘后阶段价格。<br> 关闭盘前盘后：盘前盘后阶段价格不纳入计算。</p><p>当日盈亏只计算实际的持仓数据，交易产生的手续费等不计入当日盈亏中。</p><h2 id="四、收益率计算方法" tabindex="-1">四、收益率计算方法 <a class="header-anchor" href="#四、收益率计算方法" aria-label="Permalink to &quot;四、收益率计算方法&quot;">​</a></h2><h3 id="简单加权" tabindex="-1">简单加权 <a class="header-anchor" href="#简单加权" aria-label="Permalink to &quot;简单加权&quot;">​</a></h3><p>简单加权 = 累计收益率 = 累计收益 /（期初总资产 + 期间净流入）</p><p>此方法将账户在统计区间的资金存取、股票转仓等净流入金额全部视为在期间发生，最后调整到期初资产，与期初资产合并作为投入成本。</p><p>优点：计算快速，简单易懂。</p><p>缺点：相对不准确，尤其当账户资金转出较大或计算区间较长时，可能导致收益率扭曲和夸大，甚至出现负数，失去参考价值。</p><h3 id="时间加权收益率" tabindex="-1">时间加权收益率 <a class="header-anchor" href="#时间加权收益率" aria-label="Permalink to &quot;时间加权收益率&quot;">​</a></h3><p>时间加权收益率 = [（1 + 第 1 日的当日收益率）×（1 + 第 2 日的当日收益率）× … ×（1 + 第 n 日的当日收益率）- 1] × 100%</p><p>其中：当日收益率 = 当日盈亏额 /（昨日期末资产 + 当日净投入）</p><p>净流入指资金存取和股票转仓。此方法将整个区间按天分割，先计算每天的收益率，最后计算区间累计收益率。</p><p>优点：将区间按天分割为多个时间段，尽量减少了净流入对收益率的影响。</p><p>缺点：没有考虑投资金额，而对每日收益率平等处理。如果频繁大额（相对账户净值）资金存取，可能导致收益金额与收益率符号相反，此时收益率无参考价值。</p><h2 id="五、收益日历" tabindex="-1">五、收益日历 <a class="header-anchor" href="#五、收益日历" aria-label="Permalink to &quot;五、收益日历&quot;">​</a></h2><p>收益日历为分币种计算盈亏再合计，不会受到汇率变化的影响，反馈的是真实的盈亏情况。</p><p>计算逻辑：先计算每个币种的盈亏，再进行合计并转化为港币。</p><p>A 币种盈亏 = 期末总资产（T 日）- 期初总资产（T-1 日）- 当日净投入</p><p>当日盈亏 = A 币种盈亏 × A 币种汇率 + … + N 币种盈亏 × N 币种汇率</p><p>注意：收益日历显示的盈亏和资产页的当日盈亏并不相等（详见常见问题第 6 条）。</p><h2 id="六、常见问题" tabindex="-1">六、常见问题 <a class="header-anchor" href="#六、常见问题" aria-label="Permalink to &quot;六、常见问题&quot;">​</a></h2><h3 id="_1-当天除净后-股票出现亏损" tabindex="-1">1. 当天除净后，股票出现亏损 <a class="header-anchor" href="#_1-当天除净后-股票出现亏损" aria-label="Permalink to &quot;1. 当天除净后，股票出现亏损&quot;">​</a></h3><p>当天除净后，按照最新价计算当前持仓总市值下降了，但派息是在除净之后入账，派息入账后成本才会减少。此阶段显示亏损属于正常情况。</p><h3 id="_2-持仓盈亏与当日盈亏对不上" tabindex="-1">2. 持仓盈亏与当日盈亏对不上 <a class="header-anchor" href="#_2-持仓盈亏与当日盈亏对不上" aria-label="Permalink to &quot;2. 持仓盈亏与当日盈亏对不上&quot;">​</a></h3><p>持仓盈亏是从开仓后开始计算的累计盈亏，与成本价相关。</p><p>当日盈亏代表当日股票市值对比昨日市值的价差，与股票的昨收价相关。</p><p>两者统计口径不同，不应直接对比。</p><h3 id="_3-股票卖出后再卖空-成本和盈亏没对上" tabindex="-1">3. 股票卖出后再卖空，成本和盈亏没对上 <a class="header-anchor" href="#_3-股票卖出后再卖空-成本和盈亏没对上" aria-label="Permalink to &quot;3. 股票卖出后再卖空，成本和盈亏没对上&quot;">​</a></h3><p>换了仓位方向后，盈亏会重计，相当于之前的仓位方向已经平仓了，不会继承多头的成本。</p><h3 id="_4-盈亏排行中跟个股盈亏累计对不上" tabindex="-1">4. 盈亏排行中跟个股盈亏累计对不上 <a class="header-anchor" href="#_4-盈亏排行中跟个股盈亏累计对不上" aria-label="Permalink to &quot;4. 盈亏排行中跟个股盈亏累计对不上&quot;">​</a></h3><p>两边统计的更新频率不同。盈亏排行是离线数据，每天更新一次；个股盈亏明细是实时数据，实时更新。</p><h3 id="_5-总盈亏不等于期末总资产-期初总资产" tabindex="-1">5. 总盈亏不等于期末总资产 - 期初总资产 <a class="header-anchor" href="#_5-总盈亏不等于期末总资产-期初总资产" aria-label="Permalink to &quot;5. 总盈亏不等于期末总资产 - 期初总资产&quot;">​</a></h3><p>由于为综合账户，期初期末的资产都会转化为港币进行计算，但盈亏额不考虑汇率变化。</p><p>示例：入金 10000 USD，期初汇率为 7.8，转化为港币后期初资产为 78000 HKD，无任何交易，期末资产依然是 10000 USD，期末汇率为 7.82，转化为港币资产为 78200 HKD，但盈亏实际为 0。</p><h3 id="_6-收益日历显示的盈亏和资产页的当日盈亏不相等" tabindex="-1">6. 收益日历显示的盈亏和资产页的当日盈亏不相等 <a class="header-anchor" href="#_6-收益日历显示的盈亏和资产页的当日盈亏不相等" aria-label="Permalink to &quot;6. 收益日历显示的盈亏和资产页的当日盈亏不相等&quot;">​</a></h3><p>收益日历的盈亏：拿当天的实时资产 - 日初总资产进行计算。日初总资产 = 美东 20 点的合计现金 + 合计持仓市值（只使用美股收盘价 + 港股收盘价）。美东 20 点对应北京时间：夏令时为早上 8 点，冬令时为早上 9 点。</p><p>资产页当日盈亏：（当前价格 × 当前数量）-（昨日收盘价 × 昨日收盘数量）+ 当日卖出成交额 - 当日买入成交额。按市场分开来看：当日盈亏 = 当天港股盈亏 + 昨日美股盈亏 + 基金盈亏。其中美股盈亏会根据客户开启盘前盘后价自动调整。</p>',63)])])}const b=e(o,[["render",h]]);export{u as __pageData,b as default};
